import{DIMENSIONS,MODEL_VERSION,VARIABLES,cumulativeInterventions,scoreCase,exportCsv,exportJson,importJson,printableReport}from'./core.mjs';
const KEY='cmo_migrana_cases_v1';let id=crypto.randomUUID(),pseudonym='CASO-'+Math.random().toString(36).slice(2,7).toUpperCase(),answers={},override;const $=s=>document.querySelector(s);function loadCases(){return JSON.parse(localStorage.getItem(KEY)||'[]')}function save(){const cases=loadCases().filter(c=>c.id!==id);cases.unshift({id,pseudonym,answers,override,updatedAt:new Date().toISOString(),trace:[{at:new Date().toISOString(),action:'autosave'}]});localStorage.setItem(KEY,JSON.stringify(cases))}function dl(n,t,type='application/json'){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([t],{type}));a.download=n;a.click()}function render(){const r=scoreCase(answers,override);document.title=`CMO-Migraña P${r.finalPriority}`;$('#app').innerHTML=`<header><span class="badge">${MODEL_VERSION}</span><h1>Herramienta CMO de estratificación para pacientes con migraña</h1><p class="warning">Herramienta de apoyo a la estratificación y planificación farmacéutica. No sustituye el juicio clínico, no diagnostica, no prescribe, no recomienda cambios autónomos de tratamiento, no es producto sanitario certificado y debe validarse antes de implantación asistencial.</p></header><section><h2>1. Crear o recuperar caso</h2><label>Identificación pseudonimizada<input id="pseudo" value="${pseudonym}"></label><label>Buscar casos locales<input id="search"></label><div id="cases"></div></section><section><h2>2. Formulario por dimensiones</h2><p>Progreso: ${VARIABLES.length-r.missing.length}/${VARIABLES.length}. Los datos ausentes se muestran como pendientes y no se interpretan silenciosamente como cero.</p>${Object.entries(DIMENSIONS).map(([dim,d])=>`<fieldset><legend>${d.label} — subtotal ${r.subtotals[dim]}/${d.max}</legend>${VARIABLES.filter(v=>v.dimension===dim).map(v=>`<div class="card"><label>${v.label}<select aria-label="${v.label}" data-var="${v.id}"><option value="">Pendiente</option>${v.options.map(o=>`<option value="${o.id}" ${answers[v.id]===o.id?'selected':''}>${o.label} — ${o.score} puntos</option>`).join('')}</select></label><details><summary>Definición y fuente</summary><p>${v.definition}</p><ul>${v.options.map(o=>`<li><b>${o.label}:</b> ${o.definition} (${o.score} puntos)</li>`).join('')}</ul><small>${v.sourcePage}</small></details></div>`).join('')}</fieldset>`).join('')}</section><section><h2>3. Resumen y resultado</h2>${r.pediatric?'<p class="alert">Menor de 18 años: Requiere valoración mediante modelo pediátrico. No se presenta clasificación adulta como clínicamente válida.</p>':''}${r.missing.length?`<p class="alert">Cálculo provisional: variables pendientes ${r.missing.join(', ')}.</p>`:''}<div class="priority p${r.finalPriority}"><b>Prioridad final: ${r.finalPriority}</b><br>Prioridad calculada: ${r.algorithmPriority}; prioridad numérica: ${r.numericPriority}; puntuación ${r.total}/40.</div>${r.automaticPriority?`<p>Prioridad automática: Sí. Motivo: ${r.automaticPriorityReasons.join(', ')}.</p>`:''}<h3>Contribuciones</h3><table><thead><tr><th>Variable</th><th>Opción</th><th>Puntos</th></tr></thead><tbody>${r.contributions.map(c=>`<tr><td>${c.variable}</td><td>${c.option??'Pendiente'}</td><td>${c.score??'Sin dato'}</td></tr>`).join('')}</tbody></table><h3>Override clínico</h3><select id="override" aria-label="Nueva prioridad manual"><option value="">Sin modificación manual</option><option value="1">Prioridad 1</option><option value="2">Prioridad 2</option><option value="3">Prioridad 3</option></select>${override?`<p>Modificación manual: ${override.from} → ${override.to}. Justificación: ${override.justification}. Fecha: ${override.createdAt}. Decisión profesional ajena al algoritmo original.</p>`:''}<h3>Plan de seguimiento</h3><b>Reaplicación del modelo</b><ul>${r.periodicity.model.map(x=>`<li>${x}</li>`).join('')}</ul><b>Visitas de seguimiento</b><ul>${r.periodicity.followUp.map(x=>`<li>${x}</li>`).join('')}</ul><h3>Actuaciones farmacéuticas acumulativas</h3><ul>${cumulativeInterventions(r.finalPriority).map(i=>`<li><b>P${i.priority} · ${i.category}:</b> ${i.text}</li>`).join('')}</ul></section><section><h2>4. Guardado, exportación, importación e impresión</h2><button id="save">Guardar caso</button><button id="json">Exportar JSON</button><button id="csv">Exportar CSV</button><button id="import">Importar JSON</button><button id="report">Descargar resumen clínico</button><button id="print">Imprimir informe</button><button id="del">Borrar caso</button><button id="clear">Borrar todos los datos</button></section><footer>Aplicación local privacy-first: sin analítica, sin APIs clínicas externas y sin envío intencionado de datos a servidores. La información debe ser validada por un profesional sanitario.</footer>`;$('#pseudo').oninput=e=>{pseudonym=e.target.value;save()};document.querySelectorAll('[data-var]').forEach(x=>x.onchange=e=>{answers[e.target.dataset.var]=e.target.value||undefined;save();render()});$('#override').onchange=e=>{const to=+e.target.value;if(to){const rr=scoreCase(answers);const justification=prompt('Justificación clínica obligatoria')||'';if(justification.trim()){override={from:rr.algorithmPriority,to,justification,createdAt:new Date().toISOString(),reinforcedWarningAccepted:!!(rr.automaticPriority&&to>rr.algorithmPriority)};save();render()}}};$('#save').onclick=()=>{save();alert('Caso guardado')};$('#json').onclick=()=>dl('caso-cmo-migrana.json',exportJson({id,pseudonym,answers,override,result:r}));$('#csv').onclick=()=>dl('caso-cmo-migrana.csv',exportCsv([{id,pseudonym,total:r.total,prioridad:r.finalPriority,status:r.status}]),'text/csv');$('#import').onclick=()=>{const text=prompt('Pegue JSON importado');if(text){const c=importJson(text);id=c.id||crypto.randomUUID();pseudonym=c.pseudonym||'CASO-IMPORTADO';answers=c.answers||{};override=c.override;save();render()}};$('#report').onclick=()=>dl('informe-cmo-migrana.txt',printableReport(pseudonym,answers,override),'text/plain');$('#print').onclick=()=>print();$('#del').onclick=()=>{if(confirm('¿Borrar este caso?')){localStorage.setItem(KEY,JSON.stringify(loadCases().filter(c=>c.id!==id)));alert('Borrado')}};$('#clear').onclick=()=>confirm('¿Borrar todos los datos locales?')&&localStorage.removeItem(KEY);$('#search').oninput=e=>{$('#cases').innerHTML=loadCases().filter(c=>c.pseudonym.toLowerCase().includes(e.target.value.toLowerCase())).slice(0,5).map(c=>`<button data-load="${c.id}">Recuperar ${c.pseudonym}</button>`).join('');document.querySelectorAll('[data-load]').forEach(b=>b.onclick=()=>{const c=loadCases().find(x=>x.id===b.dataset.load);id=c.id;pseudonym=c.pseudonym;answers=c.answers;override=c.override;render()})}}render();save();
